// app/src/main/java/com/smarttube/player/StreamSelector.java
package com.smarttube.player;

import java.util.List;
import java.util.Comparator;
import java.util.Optional;

/**
 * Manages the selection of the optimal video stream based on available qualities and preferences.
 */
public class StreamSelector {

    /**
     * Represents a single video stream with its resolution and other properties.
     */
    public static class VideoStream {
        private final String id;
        private final int width;
        private final int height;
        private final int bitrate; // In bits per second

        public VideoStream(String id, int width, int height, int bitrate) {
            this.id = id;
            this.width = width;
            this.height = height;
            this.bitrate = bitrate;
        }

        public String getId() {
            return id;
        }

        public int getWidth() {
            return width;
        }

        public int getHeight() {
            return height;
        }

        public int getBitrate() {
            return bitrate;
        }

        /**
         * Checks if this stream qualifies as a 4K (UHD or DCI 4K) resolution stream.
         * Common 4K resolutions are 3840x2160 (UHD) or 4096x2160 (DCI 4K).
         * This method assumes a minimum height of 2160 pixels for 4K.
         *
         * @return true if the stream's resolution is 4K or higher, false otherwise.
         */
        public boolean is4K() {
            return height >= 2160 && width >= 3840; // Covers both UHD and DCI 4K
        }

        @Override
        public String toString() {
            return "VideoStream{" +
                   "id='" + id + '\'' +
                   ", width=" + width +
                   ", height=" + height +
                   ", bitrate=" + bitrate +
                   '}';
        }
    }

    /**
     * Selects the best video stream from a list of available streams,
     * prioritizing 4K resolution if available and a preference is set.
     * If no specific preference is given, it defaults to the highest resolution available.
     *
     * @param availableStreams A list of {@link VideoStream} objects that are available for playback.
     * @param preferredResolution A string indicating a preferred resolution (e.g., "4K", "1080p").
     *                            Case-insensitive. Can be null for no specific preference.
     * @return An {@link Optional} containing the selected {@link VideoStream}, or empty if no streams are available.
     */
    public Optional<VideoStream> selectBestVideoStream(List<VideoStream> availableStreams, String preferredResolution) {
        if (availableStreams == null || availableStreams.isEmpty()) {
            return Optional.empty();
        }

        // Sort streams primarily by height (resolution), then by width, then by bitrate, all in descending order.
        // This ensures that higher quality streams are at the beginning of the list.
        availableStreams.sort(Comparator
                .comparingInt(VideoStream::getHeight)
                .thenComparingInt(VideoStream::getWidth)
                .thenComparingInt(VideoStream::getBitrate)
                .reversed());

        // If a 4K preference is explicitly stated, attempt to find and return the highest quality 4K stream.
        if (preferredResolution != null && "4K".equalsIgnoreCase(preferredResolution.trim())) {
            Optional<VideoStream> fourKStream = availableStreams.stream()
                    .filter(VideoStream::is4K)
                    .findFirst(); // Since sorted, this will be the highest quality 4K stream
            if (fourKStream.isPresent()) {
                return fourKStream;
            }
            // If 4K was preferred but no 4K stream was found, fall through to select the highest available.
        }

        // If no specific preference or 4K preference couldn't be fulfilled,
        // return the highest resolution stream available (which is the first element after sorting).
        return Optional.of(availableStreams.get(0));
    }

    /**
     * Overload for selecting the best stream without a specific preferred resolution.
     * This method will default to selecting the highest resolution stream available.
     *
     * @param availableStreams A list of {@link VideoStream} objects.
     * @return An {@link Optional} containing the selected {@link VideoStream}, or empty if no streams are available.
     */
    public Optional<VideoStream> selectBestVideoStream(List<VideoStream> availableStreams) {
        return selectBestVideoStream(availableStreams, null); // No specific resolution preference
    }
}
